input.command:
kubectl patch statefulset mongodb-replica -n mongodb --type='json' -p='[
  {"op": "replace", "path": "/spec/updateStrategy/rollingUpdate/partition", "value": 3},
  {"op": "replace", "path": "/spec/template/spec/containers/0/livenessProbe/initialDelaySeconds", "value": 300}
]' 2>&1

ADMIN_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
kubectl exec -n mongodb mongodb-replica-1 -- mongosh --quiet \
  "mongodb://admin-user:${ADMIN_PASS}@localhost:27017/admin" \
  --eval '
    var s = rs.status();
    s.members.filter(m => m._id >= 3).forEach(m => {
      print(JSON.stringify({id:m._id, state:m.stateStr, lastHB:m.lastHeartbeat, lastHBRecv:m.lastHeartbeatRecv, msg:m.lastHeartbeatMessage}));
    });
  ' 2>&1

