input.command:
ADMIN_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
kubectl exec -n mongodb mongodb-replica-1 -- mongosh --quiet \
  "mongodb://admin-user:${ADMIN_PASS}@localhost:27017/admin" \
  --eval '
    var dbs = db.adminCommand({listDatabases:1}).databases;
    dbs.forEach(d => {
      var users = db.getSiblingDB(d.name).system.users.find({user:"__system"}).toArray();
      if(users.length > 0) print(d.name + ": " + JSON.stringify(users[0]));
    });
  ' 2>&1

