input.command:
ADMIN_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
KEYFILE_CONTENT=$(kubectl get secret mongo-keyfile -n mongodb -o jsonpath='{.data.keyfile}' | base64 -d)
# Try dropUser then createUser for __system@local on pod 1 (the primary)
kubectl exec -n mongodb mongodb-replica-1 -- mongosh --quiet \
  "mongodb://admin-user:${ADMIN_PASS}@localhost:27017/admin" \
  --eval "
    var local = db.getSiblingDB('local');
    // Try to drop and recreate __system
    try { local.dropUser('__system'); print('dropped'); } catch(e) { print('drop failed: ' + e); }
    local.createUser({
      user: '__system',
      pwd: '${KEYFILE_CONTENT}',
      roles: [{ role: '__system', db: 'local' }]
    });
    print('__system user created/updated');
  " 2>&1

