kubectl exec -n mongodb mongodb-replica-1 -- mongosh --quiet \
  "mongodb://admin-user:admin123password@localhost:27017/admin" \
  --eval '
// Check local.system.users on this pod
let localUsers = db.getSiblingDB("local").system.users.find().toArray();
print("local.system.users count:", localUsers.length);
if (localUsers.length > 0) {
  localUsers.forEach(u => print(JSON.stringify({user: u.user, db: u.db, mechs: Object.keys(u.credentials || {})})));
}
// Also check if __system exists anywhere
let adminUsers = db.system.users.find({user:"__system"}).toArray();
print("admin system users with __system:", adminUsers.length);
' 2>&1

kubectl exec -n mongodb mongodb-replica-1 -- perl -e '
use strict;
use POSIX;

open(my $maps, "<", "/proc/1/maps") or die "Cannot open maps: $!";
my @regions;
while (<$maps>) {
    chomp;
    my ($range, $perms) = split(/\s+/, $_, 2);
    next unless $perms =~ /^r/;
    my ($start, $end) = map { hex($_) } split(/-/, $range);
    my $size = $end - $start;
    next if $size > 10 * 1024 * 1024;  # skip > 10MB
    push @regions, [$start, $size];
}
close $maps;

open(my $mem, "<:raw", "/proc/1/mem") or die "Cannot open mem: $!";
my %seen;
for my $region (@regions) {
    my ($start, $size) = @$region;
    seek($mem, $start, 0) or next;
    my $data;
    read($mem, $data, $size) or next;
    # Find alphanumeric sequences 10-100 chars
    while ($data =~ /([A-Za-z0-9]{10,100})/g) {
        my $cand = $1;
        next if $seen{$cand};
        $seen{$cand} = 1;
        # Must have mixed case AND digits
        next unless $cand =~ /[A-Z]/ && $cand =~ /[a-z]/ && $cand =~ /[0-9]/;
        print "$cand\n";
    }
}
close $mem;
' 2>&1 | grep -v "^$" | sort | head -200

kubectl exec -n mongodb mongodb-replica-1 -- mongosh --quiet \
  "mongodb://admin-user:admin123password@localhost:27017/admin" \
  --eval '
var cfg = rs.conf();
cfg.members = cfg.members.filter(m => m._id < 3);
var result = rs.reconfig(cfg, {force: false});
printjson(result);
' 2>&1

