kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet \
  "mongodb://admin-user:admin123password@localhost:27017/admin" \
  --eval '
rs.add("mongodb-replica-3.mongodb-replica-svc.mongodb.svc.cluster.local:27017");
rs.add("mongodb-replica-4.mongodb-replica-svc.mongodb.svc.cluster.local:27017");
printjson(rs.status().members.map(m => ({id:m._id, state:m.stateStr, health:m.health})));
' 2>&1

