input.command:
kubectl patch statefulset mongodb-replica -n mongodb --type=json -p='[
  {"op":"replace","path":"/spec/updateStrategy/rollingUpdate/partition","value":0},
  {"op":"replace","path":"/spec/template/spec/containers/0/livenessProbe/initialDelaySeconds","value":60}
]' 2>&1

# Final RS status - wait for member 3 to rejoin after its restart
sleep 10
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet \
  "mongodb://admin-user:admin123password@localhost:27017/admin" \
  --eval '
var s = rs.status();
print("Replica set:", s.set);
s.members.forEach(m => print(
  " member", m._id, "|", m.name.split(".")[0],
  "| state:", m.stateStr,
  "| health:", m.health
));
var healthy = s.members.filter(m => m.health === 1 && (m.stateStr === "PRIMARY" || m.stateStr === "SECONDARY")).length;
print("Healthy PRIMARY/SECONDARY:", healthy, "/ 5");
' 2>&1
